using Store;

namespace ShoppingCart.Tests;

[TestClass]
public class AddItemTests
{
    [TestMethod]
    public void AddItem_SingleItem_ItemIsInCart()
    {
        var cart = new Store.ShoppingCart();

        cart.AddItem("SKU-001", 1, 9.99m);

        Assert.AreEqual(9.99m, cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_AllContributeToTotal()
    {
        var cart = new Store.ShoppingCart();

        cart.AddItem("SKU-001", 1, 10.00m);
        cart.AddItem("SKU-002", 2, 5.00m);

        Assert.AreEqual(20.00m, cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_QuantitiesAccumulate()
    {
        var cart = new Store.ShoppingCart();

        cart.AddItem("SKU-001", 1, 10.00m);
        cart.AddItem("SKU-001", 3, 10.00m);

        Assert.AreEqual(40.00m, cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();

        Assert.ThrowsException<ArgumentException>(() =>
            cart.AddItem("SKU-001", 0, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativeQuantity_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();

        Assert.ThrowsException<ArgumentException>(() =>
            cart.AddItem("SKU-001", -1, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();

        Assert.ThrowsException<ArgumentException>(() =>
            cart.AddItem("SKU-001", 1, -5.00m));
    }

    [TestMethod]
    public void AddItem_NullSku_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();

        Assert.ThrowsException<ArgumentException>(() =>
            cart.AddItem(null!, 1, 10.00m));
    }

    [TestMethod]
    public void AddItem_EmptySku_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();

        Assert.ThrowsException<ArgumentException>(() =>
            cart.AddItem("", 1, 10.00m));
    }
}

[TestClass]
public class RemoveItemTests
{
    [TestMethod]
    public void RemoveItem_ExistingItem_ItemNoLongerInTotal()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", 1, 10.00m);
        cart.AddItem("SKU-002", 1, 20.00m);

        cart.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_TotalIsZero()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", 2, 15.00m);

        cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        var cart = new Store.ShoppingCart();

        Assert.ThrowsException<InvalidOperationException>(() =>
            cart.RemoveItem("NOPE"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();

        Assert.ThrowsException<ArgumentException>(() =>
            cart.RemoveItem(null!));
    }

    [TestMethod]
    public void RemoveItem_AlreadyRemoved_ThrowsInvalidOperationException()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", 1, 10.00m);
        cart.RemoveItem("SKU-001");

        Assert.ThrowsException<InvalidOperationException>(() =>
            cart.RemoveItem("SKU-001"));
    }
}

[TestClass]
public class CalculateTotalTests
{
    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        var cart = new Store.ShoppingCart();

        Assert.AreEqual(0m, cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItemWithQuantity_ReturnsPriceTimesQuantity()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", 3, 7.50m);

        Assert.AreEqual(22.50m, cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfAllLineItems()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("A", 1, 100.00m);
        cart.AddItem("B", 2, 50.00m);
        cart.AddItem("C", 5, 3.00m);

        Assert.AreEqual(215.00m, cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemoval_ExcludesRemovedItem()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("A", 1, 100.00m);
        cart.AddItem("B", 1, 50.00m);
        cart.RemoveItem("A");

        Assert.AreEqual(50.00m, cart.CalculateTotal());
    }
}

[TestClass]
public class ApplyCouponTests
{
    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", 1, 100.00m);

        cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(cart.CalculateTotal() < 100.00m);
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", 1, 100.00m);

        Assert.ThrowsException<ArgumentException>(() =>
            cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();

        Assert.ThrowsException<ArgumentException>(() =>
            cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCode_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();

        Assert.ThrowsException<ArgumentException>(() =>
            cart.ApplyCoupon(""));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_TotalRemainsZero()
    {
        var cart = new Store.ShoppingCart();

        cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_TotalNeverGoesNegative()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", 1, 1.00m);

        cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(cart.CalculateTotal() >= 0m);
    }
}

